import 'package:flutter/services.dart' show rootBundle;
import 'dart:convert';
import 'package:http/http.dart' as http;

class ProductionLogger {
  void logHttpRequest(String requestType, String url, Map<String, String> headers, Map<String, dynamic> body) async {
    String requestPayload = jsonEncode(body);
    await rootBundle.loadString('log.txt').then((content) {
      print('$requestType $url\nHeaders: $headers\nBody: $requestPayload');
      debugPrint('Log file content:\n$content');
    });
  }

  void logDatabaseOperation(String operation, Map<String, dynamic> data) async {
    await rootBundle.loadString('log.txt').then((content) {
      print('Database Operation: $operation\nData: $data');
      debugPrint('Log file content:\n$content');
    });
  }

  void logAuthFlow(String authState, String token) async {
    await rootBundle.loadString('log.txt').then((content) {
      print('Auth Flow State: $authState\nToken: $token');
      debugPrint('Log file content:\n$content');
    });
  }

  void logUserInteraction(String interaction, dynamic details) async {
    await rootBundle.loadString('log.txt').then((content) {
      print('User Interaction: $interaction\nDetails: $details');
      debugPrint('Log file content:\n$content');
    });
  }
}

void main() {
  final logger = ProductionLogger();

  // Example usage
  http.get(Uri.parse("https://example.com"), headers: {"key": "value"}).then((response) {
